"use client";

import { AnimatePresence, motion } from "framer-motion";
import { useLocale, useTranslations } from "next-intl";
import { useEffect, useMemo, useRef, useState } from "react";
import type { ChatDemoScenario } from "../chat-demo-rail";

type DemoMessage = {
  from: "user" | "bot";
  text: string;
};

const DEMO_DATE = new Date("2026-04-08T09:41:00");
const LOCK_SCREEN_MS = 1700;
const MESSAGE_STAGGER_MS = 650;
const END_HOLD_MS = 1200;

function formatDemoTime(locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    hour: "numeric",
    minute: "2-digit",
  }).format(DEMO_DATE);
}

function formatDemoDate(locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    weekday: "long",
    month: "long",
    day: "numeric",
  }).format(DEMO_DATE);
}

function buildScenarioData(
  scenario: ChatDemoScenario,
  featuresT: ReturnType<typeof useTranslations<"Features">>,
  phoneT: ReturnType<typeof useTranslations<"PhoneMockup">>,
): {
  label: string;
  lockBody: string;
  messages: DemoMessage[];
} {
  switch (scenario) {
    case "snapOrText":
      return {
        label: featuresT("snapOrText.title"),
        lockBody: phoneT("lockBodyLogging"),
        messages: [
          { from: "user", text: featuresT("chat.snapOrText.user1") },
          { from: "bot", text: featuresT("chat.snapOrText.bot1") },
        ],
      };

    case "dailySummaries":
      return {
        label: featuresT("dailySummaries.title"),
        lockBody: phoneT("lockBodySummary"),
        messages: [{ from: "bot", text: featuresT("chat.dailySummaries.bot1") }],
      };

    case "smartReminders":
      return {
        label: featuresT("smartReminders.title"),
        lockBody: phoneT("lockBodyReminder"),
        messages: [
          { from: "bot", text: featuresT("chat.smartReminders.bot1") },
          { from: "user", text: featuresT("chat.smartReminders.user1") },
        ],
      };
  }
}

export type { ChatDemoScenario };

export function ChatIMessageAnimation({
  scenario,
  playing,
  startAtEnd = false,
  onComplete,
}: {
  scenario: ChatDemoScenario;
  playing: boolean;
  startAtEnd?: boolean;
  onComplete?: () => void;
  onBackTap?: () => void;
}) {
  const locale = useLocale();
  const featuresT = useTranslations("Features");
  const phoneT = useTranslations("PhoneMockup");
  const [phase, setPhase] = useState<"lock" | "chat">("lock");
  const [visibleMessages, setVisibleMessages] = useState(0);
  const doneRef = useRef(false);

  const timeStr = useMemo(() => formatDemoTime(locale), [locale]);
  const dateStr = useMemo(() => formatDemoDate(locale), [locale]);
  const data = buildScenarioData(scenario, featuresT, phoneT);

  useEffect(() => {
    doneRef.current = false;

    if (!playing) {
      return;
    }

    const timers: Array<ReturnType<typeof setTimeout>> = [];

    if (startAtEnd) {
      setPhase("chat");
      setVisibleMessages(data.messages.length);
      return () => {
        timers.forEach(clearTimeout);
      };
    }

    setPhase("lock");
    setVisibleMessages(0);

    timers.push(
      setTimeout(() => {
        setPhase("chat");
      }, LOCK_SCREEN_MS),
    );

    data.messages.forEach((_, index) => {
      timers.push(
        setTimeout(() => {
          setVisibleMessages(index + 1);
        }, LOCK_SCREEN_MS + 250 + index * MESSAGE_STAGGER_MS),
      );
    });

    timers.push(
      setTimeout(() => {
        if (!doneRef.current) {
          doneRef.current = true;
          onComplete?.();
        }
      }, LOCK_SCREEN_MS + 250 + data.messages.length * MESSAGE_STAGGER_MS + END_HOLD_MS),
    );

    return () => {
      timers.forEach(clearTimeout);
    };
  }, [data.messages.length, onComplete, playing, scenario, startAtEnd]);

  return (
    <div className="relative h-full overflow-hidden bg-[#050505] text-white">
      <AnimatePresence mode="wait">
        {phase === "lock" ? (
          <motion.div
            key={`${scenario}-lock`}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, scale: 1.02, filter: "blur(8px)" }}
            transition={{ duration: 0.45, ease: "easeOut" }}
            className="absolute inset-0 overflow-hidden bg-[radial-gradient(circle_at_top,#1f2937_0%,#0a0a0b_50%,#050505_100%)]"
          >
            <div className="absolute inset-0 bg-[url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%2220%22 height=%2220%22 viewBox=%220 0 20 20%22%3E%3Ccircle cx=%221%22 cy=%221%22 r=%221%22 fill=%22rgba(255,255,255,0.06)%22/%3E%3C/svg%3E')]" />
            <div className="flex h-full flex-col px-7 pt-20 pb-8 text-white">
              <div className="text-center">
                <p className="text-[20px] font-medium text-white/85">{dateStr}</p>
                <p className="mt-2 text-[84px] leading-none font-semibold tracking-[-0.06em] text-white">
                  {timeStr}
                </p>
              </div>

              <motion.div
                initial={{ opacity: 0, y: 18, scale: 0.96 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ delay: 0.35, duration: 0.35 }}
                className="mt-14 rounded-[28px] border border-white/12 bg-white/10 p-4 backdrop-blur-xl"
              >
                <div className="mb-3 flex items-center gap-3">
                  <div className="flex h-10 w-10 items-center justify-center rounded-[12px] bg-imessage">
                    <span className="text-sm font-bold text-white">C</span>
                  </div>
                  <div className="min-w-0">
                    <p className="text-[13px] font-semibold text-white/95">
                      {phoneT("lockTitle")}
                    </p>
                    <p className="text-[12px] text-white/55">now</p>
                  </div>
                </div>
                <p className="text-[15px] leading-[1.35] text-white/90">
                  {data.lockBody}
                </p>
              </motion.div>

              <div className="mt-auto flex items-end justify-between text-white/80">
                <div className="flex h-12 w-12 items-center justify-center rounded-full bg-white/12 backdrop-blur-md">
                  <svg
                    width="20"
                    height="20"
                    viewBox="0 0 24 24"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      d="M12 3a5 5 0 00-5 5v3H6a2 2 0 00-2 2v6h16v-6a2 2 0 00-2-2h-1V8a5 5 0 00-5-5zm-3 8V8a3 3 0 116 0v3H9z"
                      fill="currentColor"
                    />
                  </svg>
                </div>
                <div className="flex h-12 w-12 items-center justify-center rounded-full bg-white/12 backdrop-blur-md">
                  <svg
                    width="20"
                    height="20"
                    viewBox="0 0 24 24"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      d="M9 3l-1.5 4.5L3 9l4.5 1.5L9 15l1.5-4.5L15 9l-4.5-1.5L9 3z"
                      fill="currentColor"
                    />
                  </svg>
                </div>
              </div>
            </div>
          </motion.div>
        ) : (
          <motion.div
            key={`${scenario}-chat`}
            initial={{ opacity: 0, y: 14 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.35, ease: "easeOut" }}
            className="flex h-full flex-col bg-[#050505] px-5 pt-18 pb-6 text-white"
          >
            <div className="border-b border-white/8 px-4 pb-4 text-center">
              <div className="mx-auto mb-2 flex h-10 w-10 items-center justify-center rounded-full bg-imessage">
                <span className="text-sm font-bold text-white">C</span>
              </div>
              <p className="text-[13px] font-semibold text-white">
                {phoneT("header")}
              </p>
            </div>

            <div className="flex flex-1 flex-col gap-3 px-2 pt-4">
              <AnimatePresence initial={false}>
                {data.messages.slice(0, visibleMessages).map((msg, index) => (
                  <motion.div
                    key={`${scenario}-${index}`}
                    initial={{ opacity: 0, y: 16, scale: 0.96 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 0.28, ease: "easeOut" }}
                    className={`flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
                  >
                    <div
                      className={`max-w-[84%] rounded-[22px] px-4 py-2.5 text-[13px] leading-[1.45] whitespace-pre-line ${
                        msg.from === "user"
                          ? "bg-imessage text-white"
                          : "bg-[#2a2a2c] text-white"
                      }`}
                    >
                      {msg.text}
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>

            <div className="mt-4 flex items-center gap-3 rounded-full border border-white/10 bg-black/40 px-4 py-2.5">
              <div className="h-5 w-5 rounded-full bg-white/10" />
              <span className="flex-1 text-[12px] text-white/40">
                {phoneT("inputPlaceholder")}
              </span>
              <div className="flex h-6 w-6 items-center justify-center rounded-full bg-imessage">
                <svg
                  width="11"
                  height="11"
                  viewBox="0 0 24 24"
                  fill="white"
                  xmlns="http://www.w3.org/2000/svg"
                >
                  <path d="M3.4 20.4l17.45-7.48a1 1 0 000-1.84L3.4 3.6a1 1 0 00-1.39.91L2 9.12a1 1 0 00.9 1l10.13 1.12L2.9 12.36a1 1 0 00-.9 1l.01 5.12a1 1 0 001.39.92z" />
                </svg>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
